#include<bits/stdc++.h>
#define LL long long
#define Uint unsigned int
#define ULL unsigned LL
#define pii pair<int,int>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e5+5;
string s;int n,Q,c[N],o[N],w[N];
int main(){
    //freopen("operations.in","r",stdin);
    //freopen("operations.out","w",stdout);
    cin>>s;n=s.size();s=" "+s;cin>>Q;
    for(int i=1;i<=n;i++)c[i]=c[i-1]+(s[i]=='C'),
        o[i]=o[i-1]+(s[i]=='O'),w[i]=w[i-1]+(s[i]=='W');
    while(Q--){
        int l,r;cin>>l>>r;
        int C=c[r]-c[l-1],O=o[r]-o[l-1],W=w[r]-w[l-1];
        O%=2,W%=2;if(O&&W)C++,O--,W--;
        if(O||W||!(C%2))cout<<"N";else cout<<"Y";
    }
    return 0;
}
